     2→use crate::device::serial::serial_write_bytes;
     3→use crate::pdb::{
     4→    parse_fixed_header, payload_views, validate_header_identity, PdbError, PdbHeader,
     5→};
     6→
     7→#[derive(Clone, Copy, Debug, Eq, PartialEq)]
     8→pub enum LoaderError {
     9→    RamBudgetOverflow,
    10→    AppRegionTooSmall {
    11→        required: u32,
    12→        available: u32,
    13→    },
    14→    BssOutOfBounds {
    15→        start: usize,
    16→        end: usize,
    17→        region_len: usize,
    18→    },
    19→    RelocationOutOfBounds {
    20→        offset: usize,
    21→        image_len: usize,
    22→    },
    23→    EntryOffsetOutOfBounds {
    24→        entry_offset: u32,
    25→        image_len: usize,
    26→    },
    27→}
    28→
    29→#[derive(Clone, Copy, Debug, Eq, PartialEq)]
    30→pub enum PrepareImageError {
    31→    Pdb(PdbError),
    32→    Loader(LoaderError),
    33→}
    34→
    35→#[derive(Clone, Copy, Debug, Eq, PartialEq)]
    36→pub struct PreparedImage {
    37→    pub entry_offset: u32,
    38→    pub image_size: u32,
    39→    pub total_ram: u32,
    40→    pub min_heap: u32,
    41→}
    42→
    43→impl From<PdbError> for PrepareImageError {
    44→    fn from(value: PdbError) -> Self {
    45→        Self::Pdb(value)
    46→    }
    47→}
    48→
    49→impl From<LoaderError> for PrepareImageError {
    50→    fn from(value: LoaderError) -> Self {
    51→        Self::Loader(value)
    52→    }
    53→}
    54→
    55→pub fn ram_budget_bytes(header: &PdbHeader) -> Result<u32, LoaderError> {
    56→    header
    57→        .text_size
    58→        .checked_add(header.data_size)
    59→        .and_then(|total| total.checked_add(header.bss_size))
    60→        .and_then(|total| total.checked_add(header.min_heap))
    61→        .ok_or(LoaderError::RamBudgetOverflow)
    62→}
    63→
    64→pub fn ensure_region_fit(required: u32, available: u32) -> Result<(), LoaderError> {
    65→    if required > available {
    66→        return Err(LoaderError::AppRegionTooSmall {
    67→            required,
    68→            available,
    69→        });
    70→    }
    71→
    72→    Ok(())
    73→}
    74→
    75→pub fn zero_bss_tail(
    76→    region: &mut [u8],
    77→    initialized_size: u32,
    78→    bss_size: u32,
    79→) -> Result<(), LoaderError> {
    80→    let start = initialized_size as usize;
    81→    let end = start.saturating_add(bss_size as usize);
    82→
    83→    if end > region.len() {
    84→        return Err(LoaderError::BssOutOfBounds {
    85→            start,
    86→            end,
    87→            region_len: region.len(),
    88→        });
    89→    }
    90→
    91→    region[start..end].fill(0);
    92→    Ok(())
    93→}
    94→
    95→pub fn apply_relocations(
    96→    image: &mut [u8],
    97→    reloc_table: &[u8],
    98→    load_address: u32,
    99→) -> Result<(), LoaderError> {
   100→    for entry in reloc_table.chunks_exact(4) {
   101→        let offset = u32::from_le_bytes(entry.try_into().unwrap()) as usize;
   102→        let end = offset + 4;
   103→
   104→        if end > image.len() {
   105→            return Err(LoaderError::RelocationOutOfBounds {
   106→                offset,
   107→                image_len: image.len(),
   108→            });
   109→        }
   110→
   111→        let value = u32::from_le_bytes(image[offset..end].try_into().unwrap());
   112→        let relocated = value.wrapping_add(load_address);
   113→        image[offset..end].copy_from_slice(&relocated.to_le_bytes());
   114→    }
   115→
   116→    Ok(())
   117→}
   118→
   119→/// Error returned by [`load_and_run`].
   120→#[derive(Clone, Copy, Debug, Eq, PartialEq)]
   121→pub enum LoadAndRunError {
   122→    PrepareImage(PrepareImageError),
   123→}
   124→
   125→impl From<PrepareImageError> for LoadAndRunError {
   126→    fn from(e: PrepareImageError) -> Self {
   127→        Self::PrepareImage(e)
   128→    }
   129→}
   130→
   131→/// Parse and validate `pdb`, copy the image into `region`, apply relocations,
   132→/// and call `jump_fn` with the resolved entry pointer.
   133→///
   134→/// `jump_fn` defaults to [`crate::jump::jump_to_app`] in production; pass
   135→/// a mock during tests to avoid executing arbitrary bytes on the host.
   136→///
   137→/// # Safety
   138→/// `jump_fn` must be safe to call with the entry pointer derived from `region`
   139→/// and the provided `syscalls` pointer.
   140→pub unsafe fn load_and_run(
   141→    pdb: &[u8],
   142→    region: &mut [u8],
   143→    syscalls: *const PdSyscalls,
   144→    jump_fn: unsafe fn(*const u8, *const PdSyscalls),
   145→) -> Result<(), LoadAndRunError> {
   146→    let load_addr = region.as_ptr() as u32;
   147→    let prepared = prepare_image(pdb, region, load_addr)?;
   148→    serial_write_bytes(b"LAUNCH:prepare\n");
   149→    let entry = unsafe { region.as_ptr().add(prepared.entry_offset as usize) };
   150→    serial_write_bytes(b"LAUNCH:jump\n");
   151→    unsafe { jump_fn(entry, syscalls) };
   152→    serial_write_bytes(b"LAUNCH:returned\n");
   153→    Ok(())
   154→}
   155→
   156→pub fn prepare_image(
   157→    bytes: &[u8],
   158→    region: &mut [u8],
   159→    load_address: u32,
   160→) -> Result<PreparedImage, PrepareImageError> {
   161→    let header = parse_fixed_header(bytes)?;
   162→    validate_header_identity(&header)?;
   163→
   164→    let views = payload_views(&header, bytes)?;
   165→    let total_ram = ram_budget_bytes(&header)?;
   166→    let available = u32::try_from(region.len()).unwrap_or(u32::MAX);
   167→    ensure_region_fit(total_ram, available)?;
   168→
   169→    let image_size = views.image.len();
   170→    if header.entry_offset >= header.text_size {
