   334→        match (stage, err) {
   335→            ("sd_init", StorageError::NotReady) => BootFailureKind::SdInitNotReady,
   336→            ("sd_init", _) => BootFailureKind::SdInitIo,
   337→            ("sd_capacity", StorageError::NotReady) => BootFailureKind::SdCapacityNotReady,
   338→            ("sd_capacity", _) => BootFailureKind::SdCapacityIo,
   339→            _ => BootFailureKind::None,
   340→        }
   341→    }
   342→
   343→    fn device_get_buttons() -> u32 {
   344→        unsafe {
   345→            if INPUT_PTR.is_null() {
   346→                return 0;
   347→            }
   348→            (*INPUT_PTR)
   349→                .current_button()
   350→                .map(button_id_to_mask)
   351→                .unwrap_or(0)
   352→        }
   353→    }
   354→
   355→    fn device_wait_button() -> u32 {
   356→        loop {
   357→            unsafe {
   358→                if INPUT_PTR.is_null() {
   359→                    return 0;
   360→                }
   361→                match (*INPUT_PTR).poll() {
   362→                    Ok(Some(
   363→                        event @ (ButtonEvent::Press(_)
   364→                        | ButtonEvent::LongPress(_)
   365→                        | ButtonEvent::Repeat(_)),
   366→                    )) => return button_event_to_mask(event),
   367→                    Ok(Some(ButtonEvent::Release(_))) | Ok(None) | Err(_) => {}
   368→                }
   369→            }
   370→            Delay::new().delay_millis(10);
   371→        }
   372→    }
   373→
   374→    unsafe fn device_opendir(path: *const u8, len: usize) -> i32 {
   375→        if FS_PTR.is_null() {
   376→            return -1;
   377→        }
   378→        let Ok(path) = str::from_utf8(unsafe { slice::from_raw_parts(path, len) }) else {
   379→            return -1;
   380→        };
   381→        unsafe {
   382→            (&mut *FS_PTR)
   383→                .fs_opendir(path)
   384→                .map(|h| h.to_raw())
   385→                .unwrap_or(-1)
   386→        }
   387→    }
   388→
   389→    unsafe fn device_readdir(handle: i32, dirent_buf: *mut u8) -> i32 {
   390→        if FS_PTR.is_null() {
   391→            return -1;
   392→        }
   393→        let Some(handle) = DirHandle::from_raw(handle) else {
   394→            return -1;
   395→        };
   396→
   397→        match unsafe { (&mut *FS_PTR).fs_readdir(handle) } {
   398→            Ok(Some(entry)) => {
   399→                unsafe { write_pd_dirent(dirent_buf, &entry) };
   400→                0
   401→            }
   402→            Ok(None) => 1,
   403→            Err(_) => -1,
   404→        }
   405→    }
   406→
   407→    fn device_closedir(handle: i32) -> i32 {
   408→        let Some(handle) = DirHandle::from_raw(handle) else {
   409→            return -1;
   410→        };
   411→        unsafe {
   412→            if FS_PTR.is_null() {
   413→                return -1;
   414→            }
   415→            (&mut *FS_PTR).fs_closedir(handle).map(|_| 0).unwrap_or(-1)
   416→        }
   417→    }
   418→
   419→    unsafe fn write_pd_dirent(buf: *mut u8, entry: &PdDirEntry) {
   420→        let dirent = &mut *buf.cast::<PdDirent>();
   421→        *dirent = PdDirent {
   422→            name: [0u8; 256],
   423→            entry_type: match entry.entry_type {
   424→                EntryType::File => PD_FTYPE_FILE,
   425→                EntryType::Directory => PD_FTYPE_DIR,
   426→            },
   427→            size: entry.size,
   428→        };
   429→        let mut name = [0u8; 13];
   430→        let len = format_app_name(&entry.name, &mut name);
   431→        dirent.name[..len].copy_from_slice(&name[..len]);
   432→    }
   433→
   434→    #[panic_handler]
   435→    fn panic(info: &core::panic::PanicInfo<'_>) -> ! {
   436→        serial_write_bytes(b"\r\n!!! PANIC !!!\r\n");
   437→        serial_write_fmt(format_args!("{}\r\n", info));
   438→        loop {
   439→            spin_loop();
   440→        }
   441→    }
   442→
   443→    // ── F9: Launcher + app-load Embassy task ──────────────────────────────────
   444→    #[embassy_executor::task]
   445→    async fn launcher_task(_spawner: Spawner) {
   446→        unsafe {
   447→            if TRANSPORT_PTR.is_null() || LAUNCHER_BUF_PTR.is_null() {
   448→                loop {
   449→                    spin_loop();
   450→                }
   451→            }
   452→
   453→            let launcher_buf = &mut *LAUNCHER_BUF_PTR;
   454→
   455→            if BUTTON_DIAGNOSTIC_MODE {
   456→                let mut last_event = None;
   457→                let mut last_snapshot = ButtonDiagSnapshot {
   458→                    gpio1_mv: u16::MAX,
   459→                    gpio2_mv: u16::MAX,
   460→                    gpio1_decoded: None,
   461→                    gpio2_decoded: None,
   462→                    stable: None,
   463→                    last_event: None,
   464→                };
   465→
   466→                loop {
   467→                    if INPUT_PTR.is_null() {
   468→                        render_boot_placeholder(launcher_buf, BootFailureKind::None);
   469→                        device_refresh_frame(launcher_buf);
   470→                        loop {
   471→                            spin_loop();
   472→                        }
   473→                    }
   474→
   475→                    if let Ok(event) = (&mut *INPUT_PTR).poll() {
   476→                        if let Some(event) = event {
   477→                            last_event = Some(event);
   478→                        }
   479→                    }
   480→
   481→                    let (gpio1_mv, gpio2_mv) = (&*INPUT_PTR).last_samples();
   482→                    let (gpio1_decoded, gpio2_decoded) = (&*INPUT_PTR).last_decoded();
   483→                    let snapshot = ButtonDiagSnapshot {
   484→                        gpio1_mv,
   485→                        gpio2_mv,
   486→                        gpio1_decoded,
   487→                        gpio2_decoded,
   488→                        stable: (&*INPUT_PTR).current_button(),
   489→                        last_event,
   490→                    };
   491→
   492→                    if snapshot != last_snapshot {
   493→                        render_button_diagnostics(launcher_buf, &snapshot);
   494→                        device_refresh_frame(launcher_buf);
   495→                        last_snapshot = snapshot;
   496→                    }
   497→
   498→                    Delay::new().delay_millis(20);
   499→                }
   500→            }
   501→
   502→            if FS_PTR.is_null() || APP_REGION_PTR.is_null() || PDB_BUF_PTR.is_null() {
   503→                render_boot_placeholder(launcher_buf, BOOT_FAILURE);
   504→                device_refresh_frame(launcher_buf);
   505→                loop {
   506→                    spin_loop();
   507→                }
   508→            }
   509→
   510→            let fs = &mut *FS_PTR;
   511→            let app_region = &mut (&mut *APP_REGION_PTR)[..];
   512→            let pdb_buf = &mut (&mut *PDB_BUF_PTR)[..];
   513→
   514→            loop {
   515→                let filename = run_launcher_with_refresh(fs, launcher_buf, device_refresh_frame);
   516→                serial_write_bytes(b"LAUNCH:confirm\n");
   517→                let syscalls =
   518→                    build_syscall_table(app_region.as_ptr() as u32, app_region.len() as u32);
   519→                let mode = if LAUNCH_DRY_RUN {
   520→                    JumpMode::DryRun
   521→                } else {
   522→                    JumpMode::Jump(jump_to_app)
   523→                };
   524→                let _ = load_and_run(fs, &filename, pdb_buf, app_region, &syscalls, mode);
   525→            }
   526→        }
   527→    }
   528→
   529→    #[main]
   530→    fn main() -> ! {
   531→        let config = Config::default().with_cpu_clock(CpuClock::max());
   532→        let peripherals = esp_hal::init(config);
   533→
   534→        // ── G1: USB Serial/JTAG console — must come first so panics can emit ──
   535→        let serial = SERIAL_CELL.init(UsbSerialJtag::new(peripherals.USB_DEVICE));
   536→        // SAFETY: written once before any task or panic handler runs; single-core.
   537→        unsafe {
   538→            SERIAL_PTR = serial as *mut _;
   539→            set_serial_write_fn(device_serial_write);
   540→        }
   541→        esp_println::println!("PaperDOS kernel boot");
   542→
   543→        let adc1 = unsafe { peripherals.ADC1.clone_unchecked() };
   544→        let gpio1 = unsafe { peripherals.GPIO1.clone_unchecked() };
   545→        let gpio2 = unsafe { peripherals.GPIO2.clone_unchecked() };
   546→
   547→        let tx_buf = DmaTxBuf::new(
   548→            TX_DESC.init([DmaDescriptor::EMPTY; 2]),
   549→            TX_BUF.init([0u8; 4096]),
   550→        )
   551→        .unwrap();
   552→        let rx_buf = DmaRxBuf::new(
   553→            RX_DESC.init([DmaDescriptor::EMPTY; 2]),
   554→            RX_BUF.init([0u8; 4096]),
   555→        )
   556→        .unwrap();
   557→
   558→        let mut spi_raw = spi::master::Spi::new(
   559→            peripherals.SPI2,
   560→            SpiConfig::default()
   561→                .with_frequency(Rate::from_khz(400))
   562→                .with_mode(Mode::_0),
   563→        )
   564→        .unwrap()
   565→        .with_sck(peripherals.GPIO8)
   566→        .with_mosi(peripherals.GPIO10)
   567→        .with_miso(peripherals.GPIO7);
   568→        let _ = spi_raw.write(&[0xFF; 10]);
   569→        let spi_bus = spi_raw
   570→            .with_dma(peripherals.DMA_CH0)
   571→            .with_buffers(rx_buf, tx_buf);
   572→        let spi_ref = SPI_BUS_CELL.init(Mutex::new(RefCell::new(spi_bus)));
   573→
   574→        let fs = if BUTTON_DIAGNOSTIC_MODE {
   575→            Err(BootFailureKind::None)
   576→        } else {
   577→            let sd_spi: SdSpiDevice<'static, Delay> =
   578→                CriticalSectionDevice::new(spi_ref, DummyCsPin, Delay::new()).unwrap();
   579→            DeviceFs::from_spi2(
   580→                sd_spi,
   581→                // SAFETY: GPIO12 is free for SD CS on the X4 in DIO flash mode.
   582→                unsafe { RawOutputPin::new(12) },
   583→                Delay::new(),
   584→            )
   585→            .map_err(|err| map_boot_failure("sd_init", err))
   586→        };
   587→
   588→        let display_spi = CriticalSectionDevice::new(
   589→            spi_ref,
   590→            Output::new(peripherals.GPIO21, Level::High, OutputConfig::default()),
   591→            Delay::new(),
   592→        )
   593→        .unwrap();
   594→        let mut display = X4DisplayTransport::new(
   595→            display_spi,
   596→            peripherals.GPIO4,
   597→            peripherals.GPIO5,
   598→            peripherals.GPIO6,
   599→        );
   600→        emit_reset_preamble(&mut display).unwrap();
   601→        emit_power_init_block(&mut display).unwrap();
   602→        emit_addressing_init_block(&mut display).unwrap();
   603→
   604→        // F8: Store the transport and wire all device globals before spawning tasks.
   605→        let transport_ref = TRANSPORT_CELL.init(display);
   606→        let launcher_buf_ref = LAUNCHER_BUF_CELL.init([0xFF; FRAME_BYTES]);
   607→        let app_region_ref = APP_REGION_CELL.init([0u8; APP_REGION_BYTES]);
   608→        let pdb_buf_ref = PDB_BUF_CELL.init([0u8; PDB_BUF_BYTES]);
   609→        let fs_ref = match fs {
   610→            Ok(fs) => FS_CELL.init(fs) as *mut _,
   611→            Err(failure) => {
   612→                unsafe {
   613→                    BOOT_FAILURE = failure;
   614→                }
   615→                core::ptr::null_mut()
   616→            }
   617→        };
   618→        // SAFETY: written once here before the executor starts; single-core.
   619→        unsafe {
   620→            TRANSPORT_PTR = transport_ref as *mut _;
   621→            FS_PTR = fs_ref;
   622→            LAUNCHER_BUF_PTR = launcher_buf_ref as *mut _;
   623→            APP_REGION_PTR = app_region_ref as *mut _;
   624→            PDB_BUF_PTR = pdb_buf_ref as *mut _;
   625→        }
   626→
   627→        if BUTTON_DIAGNOSTIC_MODE {
   628→            render_diag_boot_marker(launcher_buf_ref);
   629→            let _ = display_refresh_flush(transport_ref, launcher_buf_ref);
   630→        } else {
   631→            render_launcher_boot_marker(launcher_buf_ref);
   632→            let _ = display_refresh_flush(transport_ref, launcher_buf_ref);
   633→        }
   634→
   635→        let input = X4AdcSource::new(adc1, gpio1, gpio2);
   636→        let input_ref = INPUT_CELL.init(InputPoller::new(input, 2, 100));
   637→
   638→        // SAFETY: each setter is called exactly once at init; no concurrent access.
   639→        unsafe {
   640→            set_display_flush_fn(device_display_flush);
   641→            set_input_get_buttons_fn(device_get_buttons);
   642→            set_input_wait_button_fn(device_wait_button);
   643→            set_fs_opendir_fn(device_opendir);
   644→            set_fs_readdir_fn(device_readdir);
   645→            set_fs_closedir_fn(device_closedir);
   646→            INPUT_PTR = input_ref as *mut _;
   647→        }
   648→
   649→        let timers = TimerGroup::new(peripherals.TIMG0);
   650→        let software_interrupts = SoftwareInterruptControl::new(peripherals.SW_INTERRUPT);
   651→
   652→        esp_rtos::start(timers.timer0, software_interrupts.software_interrupt0);
   653→
   654→        let executor = EXECUTOR.init(esp_rtos::embassy::Executor::new());
   655→        executor.run(|spawner| {
   656→            spawner.must_spawn(launcher_task(spawner));
   657→        })
   658→    }
   659→}
   660→
   661→#[cfg(not(all(target_arch = "riscv32", target_os = "none")))]
   662→fn main() {}
